Set-StrictMode -Latest
$ErrorActionPreference = 'Stop'

# Import the module under test
BeforeAll {
    . "$PSScriptRoot/MatrixGenerator.ps1"
}

Describe 'New-BuildMatrix' {

    Context 'Basic matrix generation (cartesian product)' {

        It 'Should generate a matrix from OS, language, and feature dimensions' {
            # Arrange: a config with 2 OSes, 2 language versions, and 2 feature flags
            [hashtable]$config = @{
                os       = @('ubuntu-latest', 'windows-latest')
                language = @('3.9', '3.10')
                feature  = @('enabled', 'disabled')
            }

            # Act
            $result = New-BuildMatrix -Config $config

            # Assert: cartesian product should have 2*2*2 = 8 combinations
            $result.matrix.Count | Should -Be 8

            # Each combination should have all three keys
            foreach ($combo in $result.matrix) {
                $combo.Keys | Should -Contain 'os'
                $combo.Keys | Should -Contain 'language'
                $combo.Keys | Should -Contain 'feature'
            }
        }

        It 'Should produce correct combinations for a simple 2x2 config' {
            [hashtable]$config = @{
                os       = @('ubuntu-latest', 'windows-latest')
                language = @('3.9', '3.10')
            }

            $result = New-BuildMatrix -Config $config

            $result.matrix.Count | Should -Be 4

            # Verify specific combinations exist
            $found = $result.matrix | Where-Object {
                $_.os -eq 'ubuntu-latest' -and $_.language -eq '3.9'
            }
            $found | Should -Not -BeNullOrEmpty
        }

        It 'Should handle single-value dimensions' {
            [hashtable]$config = @{
                os       = @('ubuntu-latest')
                language = @('3.9', '3.10', '3.11')
            }

            $result = New-BuildMatrix -Config $config
            $result.matrix.Count | Should -Be 3
        }
    }
}

